#!/bin/bash
CONFIG_FILE="${1:-sentinel.conf}"; [ ! -f "$CONFIG_FILE" ] && echo "Error: Config file missing" && exit 1; source "$CONFIG_FILE"; for file in "${FILES_TO_WATCH[@]}"; do gold="/var/backups/sentinel/$(basename "$file").gold"; if [ ! -f "$gold" ]; then echo "ERROR: No golden copy for $file"; continue; fi; if md5sum "$file" 2>/dev/null | cut -d' ' -f1 | grep -q "$(md5sum "$gold" | cut -d' ' -f1)"; then echo "OK: $file integrity verified"; else sudo cp "$gold" "$file" 2>/dev/null && echo "FIXED: Restored $file" || echo "ERROR: Failed to restore $file"; fi; done
